111	export const aiFlowBuilderRouter = router({
112	  generateFlow: organizationProcedure
113	    .input(z.object({
114	      prompt: z.string().min(5).max(5000),
115	      context: z.string().optional(), // Additional context like existing workflow description
116	    }))
117	    .mutation(async ({ input, ctx }) => {
118	      const { model } = await getModelForGeneration(input.organizationId);
119	
120	      const userMessage = input.context
121	        ? `Context about existing workflow: ${input.context}\n\nUser request: ${input.prompt}`
122	        : input.prompt;
123	
124	      const result = await generateText({
125	        model,
126	        system: SYSTEM_PROMPT,
127	        prompt: userMessage,
128	        temperature: 0.3,
129	        maxOutputTokens: 4096,
130	      });
131	
132	      // Parse the response
133	      let flowData: {
134	        nodes: Array<{ id: string; type: string; label: string; position: { x: number; y: number }; config: Record<string, unknown> }>;
135	        connections: Array<{ sourceId: string; targetId: string; sourceHandle?: string; targetHandle?: string }>;
136	        description: string;
137	      };
138	
139	      try {
140	        // Try to extract JSON from the response (handle markdown code blocks)
141	        let jsonText = result.text;
142	        const jsonMatch = jsonText.match(/```(?:json)?\s*([\s\S]*?)```/);
143	        if (jsonMatch) {
144	          jsonText = jsonMatch[1];
145	        }
146	        // Also handle case where response starts with { directly
147	        const braceMatch = jsonText.match(/\{[\s\S]*\}/);
148	        if (braceMatch) {
149	          jsonText = braceMatch[0];
150	        }
151	        flowData = JSON.parse(jsonText);
152	      } catch {
153	        throw new Error("Failed to generate a valid workflow. Please try rephrasing your request.");
154	      }
155	
156	      // Validate basic structure
157	      if (!flowData.nodes || !Array.isArray(flowData.nodes) || flowData.nodes.length === 0) {
158	        throw new Error("Generated workflow has no nodes. Please try a more specific description.");
159	      }
160	
161	      // Generate proper UUIDs for nodes
162	      const idMap = new Map<string, string>();
163	      const generateUUID = () => {
164	        return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
165	          const r = Math.random() * 16 | 0;
166	          const v = c === 'x' ? r : (r & 0x3 | 0x8);
167	          return v.toString(16);
168	        });
169	      };
170	
171	      const processedNodes = flowData.nodes.map(node => {
172	        const uuid = generateUUID();
173	        idMap.set(node.id, uuid);
174	        return {
175	          id: uuid,
176	          type: node.type,
177	          label: node.label,
178	          position: node.position || { x: 400, y: 50 },
179	          config: node.config || {},
180	        };
181	      });
182	
183	      const processedConnections = (flowData.connections || []).map(conn => ({
184	        sourceId: idMap.get(conn.sourceId) || conn.sourceId,
185	        targetId: idMap.get(conn.targetId) || conn.targetId,
186	        sourceHandle: conn.sourceHandle,
187	        targetHandle: conn.targetHandle,
188	      }));
189	
190	      return {
191	        nodes: processedNodes,
192	        connections: processedConnections,
193	        description: flowData.description || "AI-generated workflow",
194	        usage: {
195	          inputTokens: result.usage?.inputTokens ?? 0,
196	          outputTokens: result.usage?.outputTokens ?? 0,
197	        },
198	      };
199	    }),
200	});
