21	  port: z.number().int().positive(),
22	  database: z.string().min(1),
23	  user: z.string().min(1),
24	  password: z.string().min(1),
25	  ssl: z.boolean().optional(),
26	});
27	
28	const mongodbConfigSchema = z.object({
29	  connectionString: z.string().min(1),
30	  database: z.string().min(1),
31	});
32	
33	const redisConfigSchema = z.object({
34	  host: z.string().min(1),
35	  port: z.number().int().positive(),
36	  password: z.string().optional(),
37	  database: z.number().int().optional(),
38	});
