68	export const credentialsRouter = router({
69	  list: organizationProcedure
70	    .input(
71	      z.object({
72	        workflowId: z.string().uuid().optional(),
73	      })
74	    )
75	    .query(async ({ ctx, input }) => {
76	      const filters = [eq(credentials.organizationId, input.organizationId)];
77	      
78	      if (input.workflowId) {
79	        filters.push(eq(credentials.workflowId, input.workflowId));
80	      } else {
81	        // If no workflowId provided, only return organization-level credentials (where workflowId is null)
82	        // OR return all? The user explicitly wants "own credentials".
83	        // Let's filter for global ones (workflowId is null) to separate them.
84	        filters.push(isNull(credentials.workflowId));
85	      }
86	
87	      const creds = await db.query.credentials.findMany({
88	        where: and(...filters),
89	        orderBy: (credentials, { desc }) => [desc(credentials.createdAt)],
90	      });
91	
92	      // Don't send encrypted config to client, just metadata
93	      return creds.map((cred) => ({
94	        id: cred.id,
95	        name: cred.name,
96	        type: cred.type,
97	        description: cred.description,
98	        createdAt: cred.createdAt,
99	        updatedAt: cred.updatedAt,
100	      }));
101	    }),
102	
103	  get: organizationProcedure
104	    .input(
105	      z.object({
106	        credentialId: z.string().uuid(),
107	      })
108	    )
109	    .query(async ({ ctx, input }) => {
110	      const cred = await db.query.credentials.findFirst({
111	        where: and(
112	          eq(credentials.id, input.credentialId),
113	          eq(credentials.organizationId, input.organizationId)
114	        ),
115	      });
116	
117	      if (!cred) {
118	        throw new TRPCError({
119	          code: "NOT_FOUND",
120	          message: "Credential not found",
121	        });
122	      }
123	
124	      // Decrypt config for editing
125	      const config = decryptObject(cred.config as string);
126	
127	      return {
128	        id: cred.id,
129	        name: cred.name,
130	        type: cred.type,
131	        workflowId: cred.workflowId,
132	        description: cred.description,
133	        config,
134	        createdAt: cred.createdAt,
135	        updatedAt: cred.updatedAt,
136	      };
137	    }),
138	
139	  create: organizationProcedure
140	    .input(
141	      z.object({
142	        name: z.string().min(1).max(255),
143	        type: z.enum(["postgres", "mysql", "mongodb", "redis", "openai", "anthropic", "google", "groq", "mistral", "ollama", "deepseek", "openrouter", "xai"]),
144	        description: z.string().optional(),
145	        workflowId: z.string().uuid().optional(),
146	        config: credentialConfigSchema,
147	      })
148	    )
149	    .mutation(async ({ ctx, input }) => {
150	      // Encrypt the config before storing
151	      const encryptedConfig = encryptObject(input.config);
152	
153	      const [credential] = await db
154	        .insert(credentials)
155	        .values({
156	          organizationId: input.organizationId,
157	          workflowId: input.workflowId,
158	          name: input.name,
159	          type: input.type,
160	          description: input.description,
161	          config: encryptedConfig,
162	        })
163	        .returning();
164	
165	      return {
166	        id: credential.id,
167	        name: credential.name,
168	        type: credential.type,
169	        description: credential.description,
170	        createdAt: credential.createdAt,
171	      };
172	    }),
173	
174	  update: organizationProcedure
175	    .input(
176	      z.object({
177	        credentialId: z.string().uuid(),
178	        name: z.string().min(1).max(255).optional(),
179	        description: z.string().optional(),
180	        config: credentialConfigSchema.optional(),
181	      })
182	    )
183	    .mutation(async ({ ctx, input }) => {
184	      // Verify ownership
185	      const existing = await db.query.credentials.findFirst({
186	        where: and(
187	          eq(credentials.id, input.credentialId),
188	          eq(credentials.organizationId, input.organizationId)
189	        ),
190	      });
191	
192	      if (!existing) {
193	        throw new TRPCError({
194	          code: "NOT_FOUND",
195	          message: "Credential not found",
196	        });
197	      }
198	
199	      const updateData: {
200	        name?: string;
201	        description?: string | null;
202	        config?: string;
203	        updatedAt: Date;
204	      } = {
205	        updatedAt: new Date(),
206	      };
207	
208	      if (input.name) {
209	        updateData.name = input.name;
210	      }
211	
212	      if (input.description !== undefined) {
213	        updateData.description = input.description;
214	      }
215	
216	      if (input.config) {
217	        updateData.config = encryptObject(input.config);
218	      }
219	
220	      const [updated] = await db
221	        .update(credentials)
222	        .set(updateData)
223	        .where(eq(credentials.id, input.credentialId))
224	        .returning();
225	
226	      return {
227	        id: updated.id,
228	        name: updated.name,
229	        type: updated.type,
230	        description: updated.description,
231	        updatedAt: updated.updatedAt,
232	      };
233	    }),
234	
235	  delete: organizationProcedure
236	    .input(
237	      z.object({
238	        credentialId: z.string().uuid(),
239	      })
240	    )
241	    .mutation(async ({ ctx, input }) => {
242	      // Verify ownership
243	      const existing = await db.query.credentials.findFirst({
244	        where: and(
245	          eq(credentials.id, input.credentialId),
246	          eq(credentials.organizationId, input.organizationId)
247	        ),
248	      });
249	
250	      if (!existing) {
251	        throw new TRPCError({
252	          code: "NOT_FOUND",
253	          message: "Credential not found",
254	        });
255	      }
256	
257	      await db.delete(credentials).where(eq(credentials.id, input.credentialId));
258	
259	      return { success: true };
260	    }),
261	
262	  testConnection: organizationProcedure
263	    .input(
264	      z.object({
265	        type: z.enum(["postgres", "mysql", "mongodb", "redis", "openai", "anthropic", "google", "groq", "mistral", "ollama", "deepseek", "openrouter", "xai"]),
266	        config: credentialConfigSchema,
267	      })
268	    )
269	    .mutation(async ({ ctx, input }) => {
270	      // Test the connection without saving
271	      try {
272	        // Connection test placeholder - returns success for now
273	        // A full implementation would test the actual database/service connection
274	        return { success: true, message: "Connection test successful" };
275	      } catch (error) {
276	        return {
277	          success: false,
278	          message: error instanceof Error ? error.message : "Connection test failed",
279	        };
280	      }
281	    }),
282	});
